class Solution:
    def totalNQueens(self, n: int) -> int:
        count = 0
        board = [[0] * n for _ in range(n)]
        def backtrack(row):
            if row == n:
                count += 1
                return
            for col in range(n):
                if valid_position(board, row, col):
                    board[row][col] = 1
                    backtrack(row + 1)
                    board[row][col] = 0
        backtrack(0)
        return count

    def valid_position(self, board, row, col):
        for i in range(row):
            if board[i][col] == 1:
                return False
        for i, j in zip(range(row), range(col, -1, -1)):
            if board[i][j] == 1:
                return False
        for i, j in zip(range(row), range(col, n)):
            if board[i][j] == 1:
                return False
        return True

