class Solution {
public:
    int totalNQueens(int n) {
        int count = 0;
        vector<vector<int>> board(n, vector<int>(n, 0));
        function<void(int)> backtrack = [
            &board, &backtrack, &count, n
        ](int row) {
            if (row == n) {
                count++;
                return;
            }
            for (int col = 0; col < n; col++) {
                if (valid_position(board, row, col)) {
                    board[row][col] = 1;
                    backtrack(row + 1);
                    board[row][col] = 0;
                }
            }
        };
        backtrack(0);
        return count;
    }

    bool valid_position(const vector<vector<int>>& board, int row, int col) const {
        for (int i = 0; i < row; i++) {
            if (board[i][col] == 1) {
                return false;
            }
        }
        for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
            if (board[i][j] == 1) {
                return false;
            }
        }
        for (int i = row, j = col; i >= 0 && j < n; i--, j++) {
            if (board[i][j] == 1) {
                return false;
            }
        }
        return true;
    }
};
